import React, { useState } from "react";
import axios from "axios";

function App() {
  const [query, setQuery] = useState("");
  const [responseHtml, setResponseHtml] = useState("");

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      const res = await axios.post("http://localhost:5000/visa-info", { query });
      setResponseHtml(res.data.html || res.data.response); // Prefer HTML if available
    } catch (error) {
      console.error(error);
      setResponseHtml("<p style='color:red'>Error fetching data. Is the backend running?</p>");
    }
  };

  return (
    <div style={{ padding: "20px", maxWidth: "800px" }}>
      <h2>Gemini Visa Info Assistant</h2>
      <form onSubmit={handleSubmit}>
        <input
          type="text"
          value={query}
          onChange={(e) => setQuery(e.target.value)}
          placeholder="Ask about visa process..."
          style={{ width: "300px", marginRight: "10px" }}
        />
        <button type="submit">Ask</button>
      </form>

      <div style={{ marginTop: "20px" }}>
        <strong>Response:</strong>
        <div
          style={{ whiteSpace: "pre-wrap" }}
          dangerouslySetInnerHTML={{ __html: responseHtml }}
        ></div>
      </div>
    </div>
  );
}

export default App;
